    _civil_doc(prefix='tpa', section='5', title='Transfer of Property Defined', domain='Property', act_name='Transfer of Property Act, 1882', focus='This provision belongs to the Transfer of Property Act, 1882 or allied property law and regulates voluntary transfer of property by act of parties. It is central in conveyancing, title disputes, mortgage enforcement, leases, gifts, and documentation practice.', consequence='The practical consequence concerns title, possession, enforceability against third parties, registration requirements, transferability limits, and remedies such as redemption, ejectment, or specific performance.', related='Registration Act, Specific Relief Act, Stamp laws, Easements, mortgage and lease disputes, and succession or partition questions', case_law='Courts examine intention of parties, nature of property, delivery of possession, registration, attestation where required, and the distinction between an agreement to transfer and an actual transfer.', procedure='conveyancing practice turns on drafting, registration, stamp compliance, possession evidence, revenue or municipal records, and the chain of title'),
