    _civil_doc(prefix='hma', section='5', title='Conditions for a Hindu Marriage', domain='Family', act_name='Hindu Marriage Act, 1955', focus='The provision belongs to Indian family law and is applied with strong attention to status, dignity, welfare, maintenance, equality, and protection from coercion or abuse. Courts balance statutory text with constitutional values and the facts of the domestic relationship.', consequence='The consequence may be recognition or invalidation of marital status, grant of divorce or judicial separation, interim or permanent maintenance, custody orders, or property directions incidental to matrimonial proceedings.', related='Family Courts Act, Hindu Adoptions and Maintenance Act, domestic violence law, guardianship law, and appellate family procedure', case_law='Courts interpret these provisions in light of dignity, cruelty jurisprudence, desertion, breakdown in practice, mutual consent safeguards, and welfare of children.', procedure='litigation usually requires pleadings, marriage proof, evidence of grounds such as cruelty or desertion, income disclosure, and, in custody matters, a welfare-focused assessment'),
